refentry.refsect1:
&reftitle.description;
#[\NoDiscard] public DateTimeImmutableDateTimeImmutable::setISODate intyear intweek intdayOfWeek1
返回一个新的 DateTimeImmutable 对象，其日期根据 ISO 8601 标准设置——使用周和日期偏移，而不是具体日期。

  &reftitle.examples;

   DateTimeImmutable::setISODate 示例

&style.oop;


<?php

$date = new DateTimeImmutable();

$newDate = $date->setISODate(2008, 2);
echo $newDate->format('Y-m-d') . "\n";

$newDate = $date->setISODate(2008, 2, 7);
echo $newDate->format('Y-m-d') . "\n";


   &example.outputs;


2008-01-07
2008-01-13



&style.procedural;


<?php

$date = date_create();

date_isodate_set($date, 2008, 2);
echo date_format($date, 'Y-m-d') . "\n";

date_isodate_set($date, 2008, 2, 7);
echo date_format($date, 'Y-m-d') . "\n";


   &example.outputs;


2008-01-07
2008-01-13




   超出范围的值会添加到其父级值


<?php

$date = new DateTimeImmutable();

$newDate = $date->setISODate(2008, 2, 7);
echo $newDate->format('Y-m-d') . "\n";

$newDate = $date->setISODate(2008, 2, 8);
echo $newDate->format('Y-m-d') . "\n";

$newDate = $date->setISODate(2008, 53, 7);
echo $newDate->format('Y-m-d') . "\n";


   &example.outputs;


2008-01-13
2008-01-14
2009-01-04




   查找某周所在的月份


<?php

$date = new DateTimeImmutable();
$newDate = $date->setISODate(2008, 14);
echo $newDate->format('n');


   &example.outputs;


3
